mapper.select:
select `tenant_asset_field_value`.*
from `tenant_asset_field_value`
join `tenant_asset_field_definition` on `tenant_asset_field_value`.`field_definition_id` =
`tenant_asset_field_definition`.`id`

    `tenant_asset_field_definition`.`status` = 1
    AND `tenant_asset_field_value`.`tenant_id` = #{tenantId}

        AND `tenant_asset_field_value`.`asset_id` in

            #{assetId}



        AND `tenant_asset_field_value`.`asset_id` in

            #{definitionId}
